insert into public.topics (id, track, category, number, title, summary, wiki, questions)
select id, track, category, number, title, summary, wiki, questions
from jsonb_to_recordset($awfjson$[{"id":"style-historyczne-zabytki","track":"wszyscy","category":"historia","number":58,"title":"Rozwój stylów historycznych na zabytkach Poznania (Trakt Królewsko-Cesarski)","summary":"Trakt Królewsko-Cesarski w Poznaniu to przestrzenny zapis ewolucji stylów: od architektury przedromańskiej i gotyku po renesans, barok, klasycyzm, historyzm i modernizm.","wiki":[{"heading":"Architektura przedromańska, romańska i gotyk","body":"Najstarsze zabytki na Ostrowie Tumskim wiążą się z chrystianizacją i Piastami: Palatium Mieszka I i kaplica Dobrawy (styl przedromański, surowość, łupany kamień - opus emplectum) oraz przedromańska i romańska bazylika w podziemiach katedry (masywność, monumentalizm). Gotyk (XIII-XVI w.) reprezentuje ceglana katedra na Ostrowie Tumskim - łuki ostre, sklepienia krzyżowo-żebrowe i gwiaździste, wąskie okna - oraz Psałteria (schodkowy szczyt z blendami) i Zamek Królewski na Wzgórzu Przemysła."},{"heading":"Renesans i barok","bullets":["Renesans (XVI w.) - Ratusz Jana Baptysty Quadro z loggią arkadową i attyką, Akademia Lubrańskiego, Pałac Górków","Cechy renesansu: harmonia, symetria, horyzontalizm, proporcje antyczne","Barok (XVII-XVIII w.) - Fara Poznańska (Jezuici, pseudokorynckie kolumny, freski Dankwarta), kościół św. Antoniego","Cechy baroku: dynamizm, teatralność, iluzjonizm, theatrum sacrum"]},{"heading":"Klasycyzm, rokoko i historyzm","bullets":["Klasycyzm (XVIII w.) - Odwach (portyk toskański) i Pałac Działyńskich (tympanon)","Rokoko - detale rzeźbiarskie, motyw muszli (rocaille), lekkość, złocenia","Historyzm (XIX-XX w.) w Dzielnicy Cesarskiej - Zamek Cesarski (neoromanizm), Teatr Wielki (neoklasycyzm), Collegium Minus (neorenesans), Złota Kaplica (neobizantynizm)"]},{"heading":"Modernizm i postmodernizm","body":"Modernizm reprezentuje Okrąglak (Marek Leykam, 1948-1954) - walec z betonowych prefabrykatów, zasada \"forma wynika z funkcji\". Postmodernizm/dekonstruktywizm to Brama Poznania ICHB (2014) - betonowy sześcian \"przecięty\" przeszkloną szczeliną kadrującą widok na gotycką katedrę, dialog współczesności z historią."}],"questions":[{"type":"abcd","q":"W jakim stylu architekt Jan Baptysta Quadro przebudował poznański Ratusz?","options":["Gotyk","Barok","Renesans","Klasycyzm"],"correct":2,"explain":"Ratusz uchodzi za jedno z najwspanialszych dzieł renesansu na północ od Alp; Quadro dodał trójkondygnacyjną loggię arkadową i attykę."},{"type":"tf","q":"Zamek Cesarski w Poznaniu zbudowano w stylu gotyckim, wzorując się na średniowiecznych katedrach.","correct":false,"explain":"Zamek Cesarski (proj. Franz Schwechten, 1910) powstał w stylu neoromańskim, by nawiązać do tradycji cesarskiej i legitymizować pruskie panowanie — nie w gotyku."},{"type":"flash","front":"Jakie cechy stylu gotyckiego widać w katedrze na Ostrowie Tumskim?","back":"Czerwona cegła (gotyk ceglany), strzeliste łuki ostre, sklepienia krzyżowo-żebrowe i gwiaździste oraz wysokie, wąskie okna z witrażami."}]},{"id":"planowanie-przestrzenne","track":"wszyscy","category":"historia","number":59,"title":"System planowania przestrzennego w Polsce","summary":"To trójstopniowy, hierarchiczny system kształtowania przestrzeni dla ochrony ładu przestrzennego i zrównoważonego rozwoju; kluczowy jest poziom gminny i władztwo planistyczne.","wiki":[{"heading":"Istota i cele","body":"System planowania przestrzennego to zespół narzędzi prawnych, instytucjonalnych i organizacyjnych służących zrównoważonemu kształtowaniu przestrzeni. Głównym celem jest ochrona ładu przestrzennego i zrównoważonego rozwoju. Podstawą prawną jest ustawa z 27 marca 2003 r. o planowaniu i zagospodarowaniu przestrzennym."},{"heading":"Struktura hierarchiczna (trójstopniowa)","bullets":["Poziom krajowy - dokument strategiczny (osie rozwoju, sieć osadnicza, korytarze transportowe), nie jest aktem prawa miejscowego","Poziom regionalny - Plan zagospodarowania przestrzennego województwa (PZPW), uchwala sejmik, nie wiąże właścicieli nieruchomości","Poziom lokalny (gminny) - kluczowy, tu zapadają decyzje wiążące dla obywatela","Zasada hierarchicznej zgodności - dokumenty niższego szczebla nie mogą być sprzeczne z wyższymi"]},{"heading":"Akty na poziomie gminy (po reformie 2023)","bullets":["Plan Ogólny Gminy - akt prawa miejscowego, obowiązkowy, dzieli gminę na strefy planistyczne (zastąpił dawne Studium)","Miejscowy Plan Zagospodarowania Przestrzennego (MPZP) - akt prawa miejscowego, fakultatywny, podstawa pozwoleń na budowę","Zintegrowany Plan Inwestycyjny (ZPI) - szczególna forma MPZP w ramach partnerstwa publiczno-prywatnego","Gmina ma władztwo planistyczne - autonomiczne prawo kształtowania polityki przestrzennej"]},{"heading":"Dualizm systemu i problemy","body":"Gdy nie ma MPZP, inwestor występuje o decyzję o Warunkach Zabudowy (WZ) opartą na zasadzie dobrego sąsiedztwa. Nadużywanie decyzji WZ prowadziło do rozlewania się miast (urban sprawl) i chaosu przestrzennego. Główne problemy: niski stopień pokrycia kraju planami (ok. 30-35%), koszty finansowe gmin, chaos przestrzenny i konflikty funkcji."}],"questions":[{"type":"abcd","q":"Na jakiej podstawie inwestor może budować, gdy na danym terenie nie ma uchwalonego MPZP?","options":["Na podstawie Planu zagospodarowania przestrzennego województwa","Na podstawie decyzji o Warunkach Zabudowy (WZ) i zasady dobrego sąsiedztwa","Na podstawie koncepcji rozwoju kraju","Bez żadnego dokumentu administracyjnego"],"correct":1,"explain":"W braku MPZP stosuje się ścieżkę decyzyjną - decyzję o Warunkach Zabudowy opartą na zasadzie dobrego sąsiedztwa (analiza urbanistyczna)."},{"type":"tf","q":"Władztwo planistyczne oznacza, że to wojewoda (administracja rządowa) decyduje o przeznaczeniu gruntów w gminie.","correct":false,"explain":"Władztwo planistyczne przysługuje samorządowi gminnemu — to gmina, nie wojewoda, autonomicznie decyduje o polityce przestrzennej na swoim obszarze."},{"type":"flash","front":"Jakie trzy akty planistyczne funkcjonują na poziomie gminy po reformie z 2023 r.?","back":"Plan Ogólny Gminy (zastąpił Studium), Miejscowy Plan Zagospodarowania Przestrzennego (MPZP) oraz Zintegrowany Plan Inwestycyjny (ZPI)."}]},{"id":"koncepcje-motywacyjne","track":"wszyscy","category":"rekreacja","number":2,"title":"Koncepcje motywacyjne udziału w aktywności rekreacyjno-turystycznej","summary":"Motywacja jako wewnętrzny stan pobudzający do działania, piramida Maslowa, teoria autodeterminacji oraz motywacja wewnętrzna i zewnętrzna.","wiki":[{"body":"Motywacja to wewnętrzny stan pobudzający jednostkę do działania; kieruje zachowaniem oraz wpływa na to, jak długo i jak intensywnie coś wykonujemy. Powstaje z różnych potrzeb i może mieć charakter rodzinny, poznawczy, historyczny, zdrowotny, społeczny, estetyczny lub duchowy."},{"heading":"Piramida potrzeb Maslowa","bullets":["Fizjologiczne — odpoczynek, sen, jedzenie (wakacje zaspokajają te potrzeby).","Bezpieczeństwa — podróże w spokojne miejsca, oderwanie od stresu.","Przynależności — wyjazdy z rodziną i przyjaciółmi, budowanie relacji.","Uznania — zdobywanie i dzielenie się nowymi doświadczeniami.","Samorealizacji — poznawanie świata, rozwój osobisty, duchowy, edukacyjny."]},{"heading":"Teoria autodeterminacji (Ryan i Deci)","body":"Wskazuje 3 kluczowe potrzeby psychologiczne: autonomię (decydowanie o sobie), kompetencję (poczucie sprawności) oraz relacje z innymi. Rekreacja pomaga je zaspokoić, dając poczucie spełnienia."},{"heading":"Motywacja wewnętrzna i zewnętrzna","bullets":["Wewnętrzna — wynika z osobistych potrzeb i przyjemności (bieganie dla satysfakcji, podróże dla poznawania świata).","Zewnętrzna — związana z nagrodą lub uniknięciem kary (udział w zawodach dla medalu)."]}],"questions":[{"type":"abcd","q":"Motywacja o charakterze estetycznym w aktywności rekreacyjno-turystycznej to przede wszystkim:","options":["chęć spędzania czasu z bliskimi","potrzeba kontaktu z przyrodą i pięknym krajobrazem","poprawa kondycji fizycznej i odreagowanie stresu","zainteresowanie historią danego miejsca"],"correct":1,"explain":"Motyw estetyczny to potrzeba kontaktu z przyrodą i pięknym krajobrazem; pozostałe odpowiadają motywom rodzinnemu, zdrowotnemu i historycznemu."},{"type":"abcd","q":"Bieganie dla własnej satysfakcji to przykład motywacji:","options":["zewnętrznej","wewnętrznej","kontrolnej","formalnej"],"correct":1,"explain":"Motywacja wewnętrzna wynika z osobistych potrzeb i przyjemności z działania."},{"type":"tf","q":"W piramidzie Maslowa wakacyjny odpoczynek i sen zaspokajają przede wszystkim potrzeby fizjologiczne.","correct":true,"explain":"Potrzeby fizjologiczne to m.in. odpoczynek, sen i jedzenie — wakacje zaspokajają właśnie ten podstawowy poziom piramidy."},{"type":"flash","front":"Czym różni się motywacja wewnętrzna od zewnętrznej?","back":"Wewnętrzna wynika z osobistych potrzeb i przyjemności; zewnętrzna z oczekiwania nagrody lub uniknięcia kary."}]},{"id":"fizjologiczne-podstawy-treningu","track":"wszyscy","category":"fizjologia","number":11,"title":"Przedstaw fizjologiczne podstawy treningu fizycznego człowieka","summary":"Trening wywołuje adaptacje fizjologiczne w wielu układach organizmu, opierając się na trzech systemach energetycznych.","wiki":[{"body":"Trening fizyczny wpływa na organizm poprzez adaptacje fizjologiczne zwiększające wydolność, siłę i sprawność. Jego podstawą jest zdolność organizmu do adaptacji do obciążeń wysiłkowych."},{"heading":"Źródła energii podczas wysiłku","bullets":["System fosfagenowy (ATP) - dostarcza energii bardzo szybko, do krótkich intensywnych wysiłków","Glikoliza beztlenowa - rozkład glukozy bez tlenu, energia od kilkudziesięciu sekund do minut, produktem jest mleczan","Metabolizm tlenowy - zachodzi w mitochondriach, wykorzystuje węglowodany i tłuszcze, do długotrwałych wysiłków"]},{"heading":"Adaptacje układów","bullets":["Mięśniowy - hipertrofia, wzrost wytrzymałości, więcej mitochondriów, lepsza koordynacja nerwowo-mięśniowa","Krążenia - wzrost objętości wyrzutowej i minutowej serca, spadek tętna spoczynkowego, więcej naczyń włosowatych, obniżenie ciśnienia i poziomu LDL","Oddechowy - większa pojemność płuc, lepsza wymiana gazowa, silniejsze mięśnie oddechowe","Nerwowy - lepsza koordynacja i czas reakcji, więcej endorfin","Metaboliczny i hormonalny - lepsze spalanie tłuszczów, większa wrażliwość na insulinę, wzrost testosteronu"]}],"questions":[{"type":"abcd","q":"Który system energetyczny dostarcza energii najszybciej, w krótkich i intensywnych wysiłkach?","options":["Metabolizm tlenowy","System fosfagenowy (ATP)","Glikoliza beztlenowa","Lipoliza"],"correct":1,"explain":"System fosfagenowy (ATP) dostarcza energii bardzo szybko i jest wykorzystywany w krótkich intensywnych wysiłkach."},{"type":"tf","q":"Glikoliza beztlenowa zachodzi bez udziału tlenu, a jej produktem jest mleczan.","correct":true,"explain":"Glikoliza beztlenowa rozkłada glukozę bez tlenu (energia na wysiłki od kilkudziesięciu sekund do kilku minut), a jej produktem ubocznym jest mleczan."},{"type":"flash","front":"Jakie zmiany w układzie mięśniowym wywołuje trening?","back":"Hipertrofia (wzrost masy i siły), wzrost wytrzymałości, większa liczba mitochondriów oraz lepsza koordynacja nerwowo-mięśniowa."}]},{"id":"metody-badania-rynku-turystycznego","track":"wszyscy","category":"marketing","number":35,"title":"Metody i techniki badania rynku turystycznego","summary":"Rynek turystyczny bada się metodami ilościowymi i jakościowymi, w oparciu o dane pierwotne i wtórne.","wiki":[{"heading":"Istota badań","body":"Badanie rynku turystycznego to proces zbierania informacji o konkurencji i turystach, ich potrzebach, zachowaniach i oczekiwaniach."},{"heading":"Badania ilościowe","body":"Celem jest uzyskanie konkretnych, liczbowych danych, które można analizować statystycznie.","bullets":["Ankiety i kwestionariusze (pytania zamknięte, skale ocen; online, telefonicznie, osobiście)","Badania opinii turystów (formularze oceny usług)","Badania popytu turystycznego (liczba turystów, cel podróży, długość pobytu, wydatki)","Zalety: duża próba, możliwość wnioskowania statystycznego. Wady: nie pokazują motywów i emocji turystów"]},{"heading":"Badania jakościowe","body":"Celem jest zrozumienie motywacji, potrzeb, opinii i zachowań turystów; dane opisowe, mniejsza liczba osób.","bullets":["Wywiady pogłębione - indywidualne rozmowy z uczestnikami rynku","Grupy fokusowe - dyskusje w małych grupach o usługach i preferencjach","Obserwacja uczestnicząca - badacz angażuje się w działanie grupy","Zalety: głębokie zrozumienie zachowań. Wady: trudne do uogólnienia, wymagają czasu i zasobów"]},{"heading":"Źródła danych","bullets":["Badania pierwotne - dane zbierane samodzielnie od respondentów (ankieta, wywiad, obserwacja)","Badania wtórne - wykorzystanie istniejących danych, raportów, statystyk i publikacji"]}],"questions":[{"type":"abcd","q":"Która metoda należy do badań jakościowych rynku turystycznego?","options":["Grupa fokusowa","Ankieta zamknięta","Analiza danych liczbowych ze statystyk","Badanie popytu turystycznego"],"correct":0,"explain":"Grupa fokusowa to badanie jakościowe; pozostałe wymienione to metody ilościowe."},{"type":"tf","q":"Główną wadą badań ilościowych jest to, że nie ukazują motywów ani emocji turystów.","correct":true,"explain":"Badania ilościowe dostarczają danych liczbowych do analizy statystycznej, ale nie wyjaśniają motywów i emocji — te poznaje się w badaniach jakościowych (wywiady pogłębione, grupy fokusowe)."},{"type":"flash","front":"Omów podstawowe metody i techniki badania rynku turystycznego.","back":"Badania ilościowe (ankiety, badania opinii i popytu - dane liczbowe) oraz jakościowe (wywiady pogłębione, grupy fokusowe, obserwacja uczestnicząca - zrozumienie motywacji). Obie grupy prowadzi się jako badania pierwotne (zbierane samodzielnie) lub wtórne (istniejące dane)."}]},{"id":"roznice-konflikty-kulturowe","track":"przygodowa","category":"outdoor","number":20,"title":"Roznice i konflikty kulturowe we wspolczesnym swiecie","summary":"Roznice kulturowe sa zrodlem bogactwa i konfliktow; ich podloze stanowia m.in. etnocentryzm, stereotypy, uprzedzenia i ksenofobia, a domenami konfliktow sa terytorium, jezyk i religia.","wiki":[{"body":"Roznice kulturowe sa powszechne i stanowia zarowno zrodlo bogactwa, jak i potencjalnych konfliktow. Wzrost migracji, globalizacja i wieksza swiadomosc innych kultur prowadza do wiekszej ekspozycji na roznice, ale takze do napiec. Konflikty moga wynikac ze zderzenia kultur, np. podroze w celu zobaczenia \"dzikiego\", spotkanie kultur religijnych, zderzenie codzienne czy zderzenie stereotypowe."},{"heading":"Zjawiska prowadzace do konfliktow","bullets":["Etnocentryzm - przekonanie, ze wlasne etno zajmuje centralne, uprzywilejowane miejsce i ocenia innych przez pryzmat wlasnych przekonan","Ludzkie zoo (kanibalizm turystyczny) - traktowanie przedstawicieli innej kultury przedmiotowo, jak atrakcje","Zle pojmowana autentycznosc - turysta nie dopuszcza odstepstw od swojego obrazu tubylca","Stereotypy - uproszczony, emocjonalny i czesto falszywy obraz osoby lub grupy","Uprzedzenie - negatywne nastawienie emocjonalne oparte na stereotypie","Ksenofobia - lek przed poznawaniem nowych, nieznanych osob","Dyskryminacja - skutek uprzedzen, odrzucenie osoby lub grupy","Rasizm - odrzucenie ze wzgledu na kolor skory; Eksterminacja - likwidacja grupy narodowosciowej"]},{"heading":"Zasada DIE i domeny konfliktow","body":"Dla unikania konfliktow wazna jest zasada DIE: Description (opis - to co widze), Interpretation (interpretacja - to co mysle), Evaluation (ewaluacja - to co oceniam). W modelu blednym pomijamy opis i przechodzimy od razu do oceny.","bullets":["Trzy zasadnicze domeny konfliktow kulturowych: terytorium, jezyk i religia","Spory o terytorium: np. pakistansko-indyjski o Kaszmir, japonsko-rosyjski o Kuryle, argentynsko-brytyjski o Falklandy/Malwiny","Spory o jezyk: np. Flamandowie w Belgii, Katalonczycy w Hiszpanii","Konflikty religijne: miedzy religiami swiatowymi i w ramach odlamow (np. katolicy/protestanci w Irlandii Polnocnej)"]}],"questions":[{"type":"abcd","q":"Co opisuje zasada DIE wspierajaca komunikacje miedzykulturowa?","options":["Opis sytuacji, interpretacje i ewaluacje (description, interpretation, evaluation)","Dialog, integracje i edukacje","Decyzje, implementacje i ewaluacje","Dyskryminacje, izolacje i eksterminacje"],"correct":0,"explain":"Zasada DIE sklada sie z opisu sytuacji (description), interpretacji (interpretation) i ewaluacji (evaluation). Pominiecie opisu prowadzi do konfliktu."},{"type":"abcd","q":"Ktore sa trzy zasadnicze domeny konfliktow kulturowych?","options":["Wiek, plec i wyksztalcenie","Ekonomia, technologia i ekologia","Terytorium, jezyk i religia","Sport, sztuka i nauka"],"correct":2,"explain":"Wyrozniamy trzy zasadnicze domeny konfliktow kulturowych: terytorium, jezyk i religia."},{"type":"tf","q":"Ksenofilia to lek przed poznawaniem nowych, nieznanych osob, ktory objawia sie izolacja i niecheicia.","correct":false,"explain":"Taki lek to ksenofobia; ksenofilia oznacza przeciwnie — sympatie i upodobanie do tego, co obce i nieznane."},{"type":"flash","front":"Na czym polega zjawisko \"ludzkiego zoo\" (kanibalizm turystyczny)?","back":"To przedmiotowe traktowanie przedstawicieli innej kultury — jak atrakcji turystycznej do ogladania — bez poszanowania ich podmiotowosci i godnosci."}]},{"id":"miekkie-formy-aktywnosci-terenowej","track":"przygodowa","category":"outdoor","number":11,"title":"Miękkie formy aktywności terenowej","summary":"Miękkie formy turystyki przygodowej charakteryzują się niskim ryzykiem i dostępnością bez specjalnego przygotowania; należą do nich m.in. bieg na orientację, safari, nurkowanie, narciarstwo, snowboard i surfing.","wiki":[{"heading":"Definicja miękkich form","body":"Miękkie formy aktywności turystyki przygodowej charakteryzują się niskim stopniem ryzyka i są dostępne dla osób bez specjalnych umiejętności czy przygotowania. W przeciwieństwie do twardej turystyki przygodowej, wymagającej zaawansowanych umiejętności i wiążącej się z większym ryzykiem, koncentrują się na przeżyciu przygody w bezpieczny i relatywnie łatwy sposób."},{"heading":"Przykłady miękkich form","bullets":["Bieg na orientację (BnO) - bieg wyznaczoną trasą z mapą i kompasem do punktów kontrolnych w określonej kolejności, łączący wysiłek fizyczny i intelektualny","Safari - podróż do dzikich obszarów w celu obserwacji zwierząt w naturalnym środowisku, np. Wielkiej Piątki: lwów, słoni, nosorożców, lampartów i bawołów","Nurkowanie - przebywanie pod wodą ze sprzętem lub na zatrzymanym oddechu (freediving); odmiany: snorkeling, freediving, płetwonurkowanie, wrakowe, jaskiniowe","Narciarstwo - przemieszczanie się na nartach; formy: klasyczne, biegi, skitouring, freeskiing, alpejskie","Snowboard - jazda na desce po stoku, rozwijająca równowagę, siłę mięśni i koordynację","Surfing - jazda na desce po fali morskiej; rodzaje: longboarding, shortboarding, na dużych falach, w rurkach"]}],"questions":[{"type":"abcd","q":"Czym charakteryzuje się freediving jako odmiana nurkowania?","options":["Nurkowanie ze sprzętem powietrznym w jaskiniach","Nurkowanie na zatrzymanym oddechu, bez aparatu oddechowego","Pływanie z maską wyłącznie przy powierzchni wody (snorkeling)","Nurkowanie dozwolone tylko przy wrakach statków"],"correct":1,"explain":"Freediving to nurkowanie na zatrzymanym oddechu, bez aparatu oddechowego; inne odmiany nurkowania to m.in. snorkeling, płetwonurkowanie, wrakowe i jaskiniowe."},{"type":"abcd","q":"Które zwierzęta tworzą tzw. Wielką Piątkę, będącą pożądanym celem safari?","options":["Słonie, nosorożce, krokodyle, lwy i goryle","Lwy, żyrafy, zebry, hieny i gepardy","Lwy, słonie, nosorożce, lamparty i bawoły","Lamparty, tygrysy, lwy, niedźwiedzie i wilki"],"correct":2,"explain":"Wielką Piątkę tworzą lwy, słonie, nosorożce, lamparty i bawoły."},{"type":"tf","q":"Bieg na orientację wymaga zarówno sprawności fizycznej, jak i zdolności intelektualnych.","correct":true,"explain":"BnO łączy wysiłek fizyczny (bieganie, pokonywanie przeszkód) ze zdolnościami intelektualnymi (czytanie mapy, decyzje nawigacyjne)."},{"type":"flash","front":"Wymień przykłady miękkich form aktywności terenowej.","back":"Bieg na orientację, safari, nurkowanie, narciarstwo, snowboard i surfing."}]},{"id":"rek-rekreacja-a-rozwiazywanie-konfliktow","track":"rekreacja","category":"rekreacja-spec","number":23,"title":"Wpływ rekreacji na rozwiązywanie konfliktów społecznych i zawodowych","summary":"Dzięki funkcji katartycznej i budowaniu relacji rekreacja sprzyja zdrowej komunikacji oraz radzeniu sobie ze stresem, co ułatwia rozwiązywanie konfliktów.","wiki":[{"heading":"Funkcja katartyczna","body":"Funkcja katartyczna (oczyszczająca) odnosi się do możliwości emocjonalnego odreagowania napięć i stresów poprzez aktywność fizyczną lub inne formy rekreacji. Jest to proces uwalniania negatywnych emocji prowadzący do odprężenia i poprawy samopoczucia, ważny dla zachowania równowagi psychicznej i fizycznej. Pozwala na odprężenie i redukcję stresu (ruch uwalnia endorfiny), uwolnienie emocji oraz katharsis, czyli oczyszczenie następujące po uwolnieniu napięć."},{"heading":"Wpływ na konflikty społeczne","bullets":["poprawa komunikacji poprzez wspólny sport i gry zespołowe","budowanie relacji, zaufania i empatii","redukcja stresu i napięcia towarzyszącego konfliktom","wzrost umiejętności negocjacyjnych dzięki grom zespołowym","tworzenie pozytywnej atmosfery wzajemnego szacunku"]},{"heading":"Wpływ na konflikty zawodowe","bullets":["budowanie zespołu poprzez wyjazdy integracyjne","poprawa komunikacji w zespole","redukcja stresu w pracy","rozwijanie umiejętności rozwiązywania konfliktów wymagających współpracy i negocjacji"]}],"questions":[{"type":"abcd","q":"W jaki sposób funkcja katartyczna rekreacji wspiera rozwiązywanie konfliktów społecznych?","options":["Redukuje stres i napięcie towarzyszące konfliktom poprzez odreagowanie emocji","Eliminuje konieczność komunikacji między stronami sporu","Zastępuje negocjacje rywalizacją sportową","Gwarantuje wygraną jednej ze stron konfliktu"],"correct":0,"explain":"Funkcja katartyczna pozwala odreagować napięcie i stres towarzyszące konfliktom, co — obok poprawy komunikacji i budowania relacji — ułatwia ich rozwiązywanie."},{"type":"tf","q":"Wyjazdy integracyjne i inne formy rekreacji mogą pomóc w budowaniu silnego zespołu, co zapobiega konfliktom zawodowym.","correct":true,"explain":"Budowanie zespołu poprzez wyjazdy integracyjne sprawia, że pracownicy chętniej współpracują, co przeciwdziała konfliktom zawodowym."},{"type":"flash","front":"W jaki sposób rekreacja wpływa na rozwiązywanie konfliktów społecznych?","back":"Poprawia komunikację, buduje relacje oparte na zaufaniu i empatii, redukuje stres, zwiększa umiejętności negocjacyjne i tworzy pozytywną atmosferę wzajemnego szacunku."}]},{"id":"rek-zachowania-zdrowotne","track":"rekreacja","category":"rekreacja-spec","number":27,"title":"Zachowania zdrowotne: prozdrowotne i ryzykowne","summary":"Zachowania zdrowotne to działania i nawyki wpływające na zdrowie pozytywnie (prozdrowotne) lub negatywnie (ryzykowne), a o samym zdrowiu najsilniej decyduje styl życia.","wiki":[{"heading":"Pojęcie zdrowia i jego uwarunkowania","body":"Zdrowie to nie tylko brak choroby czy kalectwa, ale stan pełnego dobrostanu fizycznego, umysłowego i społecznego. Obejmuje wymiary: fizyczny, psychiczny, społeczny, umysłowy, duchowy i seksualny. Na zdrowie najmocniej wpływa styl życia (50%), następnie czynniki genetyczne (20%), środowisko fizyczne i społeczne (20%) oraz służba zdrowia (10%). Kluczowe są też zdolność organizmu do utrzymania homeostazy oraz zasady salutogenezy, koncentrującej się na czynnikach sprzyjających zdrowiu."},{"heading":"Zachowania prozdrowotne","bullets":["aktywność fizyczna – regularne uprawianie sportu lub innej aktywności ruchowej","zdrowe odżywianie – posiłki bogate w warzywa, owoce, produkty pełnoziarniste, chude białko i zdrowe tłuszcze","unikanie używek oraz dbanie o higienę osobistą","regularne profilaktyczne wizyty u lekarza","wystarczająca ilość snu (7–8 h)","radzenie sobie ze stresem poprzez techniki relaksacyjne i aktywność fizyczną"]},{"heading":"Zachowania ryzykowne","bullets":["palenie tytoniu i nadużywanie alkoholu","niezdrowe odżywianie – dieta bogata w tłuszcze i cukry","brak aktywności fizycznej oraz stosowanie używek","zaniedbywanie zdrowia – brak wizyt u lekarza, ignorowanie objawów, samoleczenie","nadmierny, długotrwały stres","zbyt długie przesiadywanie z telefonem, komputerem lub telewizorem"]}],"questions":[{"type":"abcd","q":"Który czynnik w największym stopniu wpływa na zdrowie człowieka?","options":["Styl życia (ok. 50%)","Czynniki genetyczne (ok. 20%)","Środowisko fizyczne i społeczne (ok. 20%)","Służba zdrowia (ok. 10%)"],"correct":0,"explain":"Według podanych proporcji styl życia odpowiada za około 50% wpływu na zdrowie, najwięcej spośród wszystkich czynników."},{"type":"tf","q":"Zbyt długie przesiadywanie z telefonem, komputerem lub telewizorem zaliczane jest do zachowań prozdrowotnych.","correct":false,"explain":"To zachowanie ryzykowne; do zachowań prozdrowotnych należą m.in. aktywność fizyczna, zdrowe odżywianie, unikanie używek i wystarczająca ilość snu (7–8 h)."},{"type":"tf","q":"Salutogeneza koncentruje się głównie na poszukiwaniu czynników chorobotwórczych i przyczyn chorób.","correct":false,"explain":"Salutogeneza koncentruje się na poszukiwaniu czynników sprzyjających zdrowiu i budowaniu zasobów pomagających adaptować się do stresorów."},{"type":"flash","front":"Wymień przykładowe zachowania ryzykowne zagrażające zdrowiu.","back":"Palenie tytoniu, nadużywanie alkoholu, niezdrowe odżywianie (dieta bogata w tłuszcze i cukry), brak aktywności fizycznej, stosowanie używek, zaniedbywanie zdrowia, nadmierny długotrwały stres oraz zbyt długie przesiadywanie z telefonem, komputerem lub telewizorem."}]}]$awfjson$::jsonb)
  as x(id text, track text, category text, number int, title text, summary text, wiki jsonb, questions jsonb)
on conflict (id) do update set
  track = excluded.track,
  category = excluded.category,
  number = excluded.number,
  title = excluded.title,
  summary = excluded.summary,
  wiki = excluded.wiki,
  questions = excluded.questions;
